/*
 * PHASE-07B FROZEN TURN EXTENSION INTERFACE
 *
 * A turn always resolves in this order:
 * 1. the player action resolves through built-in handling or the action-resolver
 *    registry;
 * 2. every other actor runs exactly once in stable actor-id order;
 * 3. end-of-turn tick hooks run in this fixed order:
 *    damageOverTime -> durations -> hunger -> regen.
 *
 * Frozen extension surface:
 * - registerActionResolver handles move/attack/use_item/pickup/talk/inspect.
 * - registerTickHook handles damageOverTime/durations/hunger/regen.
 * - TurnHooks.actorTurn handles non-player actors in stable actor-id order.
 * - TurnHooks.ticks handles per-step tick overrides.
 *
 * Do not rename action kinds or TickHookName values, reorder TICK_HOOK_ORDER, or
 * let resolvers/hooks call ambient nondeterminism or LLMs. Resolvers and hooks
 * must return deterministic state/events.
 */

import { bounds, config, type GameConfig } from "../../config/index.js";
import { createClock } from "../clock/index.js";
import {
  ACTIVE_TERMINAL_STATUS,
  createInitialState,
  type EngineLogEvent,
  type EntityId,
  type EntityInstance,
  type GameState,
  type TerminalStatus,
} from "../state/index.js";
import {
  checkActionLegality,
  type PlayerAction,
} from "./actions.js";

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly action_illegal: {
      readonly actionKind: PlayerAction["kind"];
      readonly reason: string;
    };
    readonly action_resolved: {
      readonly actionKind: PlayerAction["kind"];
    };
    readonly actor_turn: {
      readonly actorId: EntityId;
    };
    readonly tick_hook: {
      readonly hook: TickHookName;
    };
    readonly terminal_state: {
      readonly status: Exclude<TerminalStatus, "ACTIVE">;
      readonly reason: string;
    };
  }
}

export { checkActionLegality, getAvailableActions } from "./actions.js";
export type {
  AbortAction,
  ActionLegality,
  ActionTarget,
  AttackAction,
  DescendAction,
  InspectAction,
  MoveAction,
  MoveDirection,
  PickupAction,
  PlayerAction,
  TalkAction,
  UseItemAction,
  WaitAction,
} from "./actions.js";

export type TurnEvent = EngineLogEvent;

export type ActorEntity = Extract<EntityInstance, { readonly kind: "enemy" | "npc" }>;

export type ActionResolverActionKind =
  | "move"
  | "attack"
  | "use_item"
  | "pickup"
  | "talk"
  | "inspect";

export type ActionResolverAction = Extract<
  PlayerAction,
  { readonly kind: ActionResolverActionKind }
>;

export type ActionResolverSuccess = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type ActionResolverIllegal = {
  readonly illegal: true;
  readonly reason: string;
};

export type ActionResolverResult =
  | ActionResolverSuccess
  | ActionResolverIllegal;

export type ActionResolver<
  Action extends ActionResolverAction = ActionResolverAction,
> = (state: GameState, action: Action) => ActionResolverResult;

export type TickHookName =
  | "damageOverTime"
  | "durations"
  | "hunger"
  | "regen";

export const TICK_HOOK_ORDER = [
  "damageOverTime",
  "durations",
  "hunger",
  "regen",
] as const satisfies readonly TickHookName[];

export type TurnHookResult =
  | GameState
  | {
      readonly state: GameState;
      readonly events?: readonly TurnEvent[];
    };

export type ActorTurnHook = (context: {
  readonly state: GameState;
  readonly actor: ActorEntity;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHook = (context: {
  readonly state: GameState;
  readonly hook: TickHookName;
  readonly action: PlayerAction;
}) => TurnHookResult;

export type TickHooks = {
  readonly [Hook in TickHookName]: TickHook;
};

export type TurnHooks = {
  readonly actorTurn?: ActorTurnHook;
  readonly ticks?: Partial<TickHooks>;
};

export type ResolvedTurnHooks = {
  readonly actorTurn: ActorTurnHook;
  readonly ticks: TickHooks;
};

export type StepOptions = {
  readonly hooks?: TurnHooks;
};

export type StepResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
};

export type StartContent = {
  readonly config?: GameConfig;
};

const actionResolvers = new Map<ActionResolverActionKind, ActionResolver>();
const tickHookRegistry = new Map<TickHookName, TickHook>();

export const registerActionResolver = <
  Kind extends ActionResolverActionKind,
>(
  actionType: Kind,
  resolver: ActionResolver<Extract<PlayerAction, { readonly kind: Kind }>>,
): (() => void) => {
  const previous = actionResolvers.get(actionType);
  const registeredResolver = resolver as ActionResolver;
  actionResolvers.set(actionType, registeredResolver);

  return () => {
    if (actionResolvers.get(actionType) !== registeredResolver) {
      return;
    }

    if (previous === undefined) {
      actionResolvers.delete(actionType);
      return;
    }

    actionResolvers.set(actionType, previous);
  };
};

export const registerTickHook = (
  slot: TickHookName,
  hook: TickHook,
): (() => void) => {
  const previous = tickHookRegistry.get(slot);
  tickHookRegistry.set(slot, hook);

  return () => {
    if (tickHookRegistry.get(slot) !== hook) {
      return;
    }

    if (previous === undefined) {
      tickHookRegistry.delete(slot);
      return;
    }

    tickHookRegistry.set(slot, previous);
  };
};

export const start = (seed: string, content: StartContent = {}): GameState =>
  createInitialState(seed, content.config ?? config);

export const step = (
  state: GameState,
  action: PlayerAction,
  options: StepOptions = {},
): StepResult => {
  if (isTerminal(state)) {
    return illegalStep(
      state,
      action,
      `run is terminal (${state.run.terminalStatus})`,
    );
  }

  const legality = checkActionLegality(state, action);
  if (legality.status === "illegal") {
    return illegalStep(state, action, legality.reason);
  }

  const forcedTerminal = forcedTerminalFor(state);
  if (forcedTerminal !== null) {
    return terminalStep(state, forcedTerminal.status, forcedTerminal.reason);
  }

  const hooks = resolveTurnHooks(options.hooks);
  const playerActionResult = applyPlayerAction(state, action);
  if (isActionResolverIllegal(playerActionResult)) {
    return illegalStep(state, action, playerActionResult.reason);
  }

  const events: TurnEvent[] = [
    turnEvent(state.run.turn, "action_resolved", {
      actionKind: action.kind,
    }),
    ...playerActionResult.events,
  ];

  let nextState = playerActionResult.state;

  if (!isTerminal(nextState)) {
    for (const actor of actorsInTurnOrder(nextState)) {
      events.push(
        turnEvent(nextState.run.turn, "actor_turn", {
          actorId: actor.id,
        }),
      );

      const result = normalizeHookResult(
        hooks.actorTurn({
          state: nextState,
          actor,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    for (const hook of TICK_HOOK_ORDER) {
      events.push(
        turnEvent(nextState.run.turn, "tick_hook", {
          hook,
        }),
      );

      const result = normalizeHookResult(
        hooks.ticks[hook]({
          state: nextState,
          hook,
          action,
        }),
      );
      nextState = result.state;
      events.push(...result.events);

      if (isTerminal(nextState)) {
        break;
      }
    }
  }

  if (!isTerminal(nextState)) {
    nextState = advanceTurn(nextState);

    const terminal = forcedTerminalFor(nextState);
    if (terminal !== null) {
      nextState = withTerminalStatus(nextState, terminal.status);
      events.push(
        turnEvent(nextState.run.turn, "terminal_state", {
          status: terminal.status,
          reason: terminal.reason,
        }),
      );
    }

import { bounds } from "../../config/index.js";
import type {
  ItemCategory,
  ItemDefinition
} from "../../schemas/entities/index.js";
import type {
  Effect,
  EffectVerbKind,
  StatusApplication,
  StatusId
} from "../../schemas/vocab/index.js";
import type { CombatActorId, DeathAttribution } from "../systems/combat.js";
import { applyDeath, deriveCombatStats } from "../systems/combat.js";
import { applyNutrition } from "../systems/player.js";
import { applyStatus, type StatusEntityId } from "../systems/status.js";
import type {
  EnemyEntityInstance,
  EntityId,
  EntityInstance,
  GameState,
  InventorySlot,
  PlayerItemStack
} from "../state/index.js";
import {
  effectExecutedEvent,
  registerEffectExecutor,
  rejectEffect,
  type EffectActorId,
  type EffectExecutionContext,
  type EffectExecutor,
  type EffectExecutorResult
} from "./registry.js";

type CoreEffectVerb =
  | "damage"
  | "heal"
  | "apply_status"
  | "cure_status"
  | "buff_stat"
  | "nutrition"
  | "identify"
  | "enchant";

type ActorWithHp =
  | {
      readonly id: "player";
      readonly hpCurrent: number;
      readonly hpMax: number;
    }
  | {
      readonly id: EntityId;
      readonly entity: EnemyEntityInstance;
      readonly hpCurrent: number;
      readonly hpMax: number;
    };

type RuntimeBuffStatus = StatusApplication & {
  readonly kind: "buff_stat";
  readonly stat: "ATK" | "DEF";
  readonly magnitude: number;
};

const CORE_EXECUTORS = {
  damage: executeDamage,
  heal: executeHeal,
  apply_status: executeApplyStatus,
  cure_status: executeCureStatus,
  buff_stat: executeBuffStat,
  nutrition: executeNutrition,
  identify: executeIdentify,
  enchant: executeEnchant
} as const satisfies Record<CoreEffectVerb, EffectExecutor>;

export const registerCoreEffectExecutors = (): (() => void) => {
  const unregisterers = Object.entries(CORE_EXECUTORS).map(([verb, executor]) =>
    registerEffectExecutor(verb as EffectVerbKind, executor)
  );

  return () => {
    for (let index = unregisterers.length - 1; index >= 0; index -= 1) {
      unregisterers[index]?.();
    }
  };
};

export const unregisterCoreEffectExecutors = registerCoreEffectExecutors();

function executeDamage(
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
): EffectExecutorResult {
  if (effect.damage === null) {
    return missingPayload(state, effect, ctx);
  }

  const amount = effect.damage.amount;
  const amountBounds = bounds.effectVocabulary.verbs.damage.amount;
  if (!isSafeIntegerInBounds(amount, amountBounds)) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      `damage.amount must be ${amountBounds.min}-${amountBounds.max}`,
      ctx
    );
  }

  const target = resolveHpTarget(state, ctx);
  if (target === null) {
    return invalidTarget(
      state,
      effect,
      ctx,
      "damage requires a player or enemy target"
    );
  }

  const hpAfter = Math.max(0, target.hpCurrent - amount);
  const damagedState = withActorHp(state, target, hpAfter);
  const executed = effectExecutedEvent(
    state,
    "damage",
    withResolvedTarget(ctx, target.id),
    {
      amount,
      hpBefore: target.hpCurrent,
      hpAfter
    }
  );

  if (hpAfter > 0) {
    return {
      state: damagedState,
      events: [executed]
    };
  }

  const death = applyDeath(damagedState, target.id, {
    attribution: deathAttributionFor(ctx.sourceId)
  });

  return {
    state: death.state,
    events: [executed, ...death.events]
  };
}

function executeHeal(
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
): EffectExecutorResult {
  if (effect.heal === null) {
    return missingPayload(state, effect, ctx);
  }

  const amount = effect.heal.amount;
  const amountBounds = bounds.effectVocabulary.verbs.heal.amount;
  if (!isSafeIntegerInBounds(amount, amountBounds)) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      `heal.amount must be ${amountBounds.min}-${amountBounds.max}`,
      ctx
    );
  }

  const target = resolveHpTarget(state, ctx);
  if (target === null) {
    return invalidTarget(
      state,
      effect,
      ctx,
      "heal requires a player or enemy target"
    );
  }

  const hpAfter = Math.min(target.hpMax, target.hpCurrent + amount);

  return {
    state: withActorHp(state, target, hpAfter),
    events: [
      effectExecutedEvent(state, "heal", withResolvedTarget(ctx, target.id), {
        amount,
        hpBefore: target.hpCurrent,
        hpAfter
      })
    ]
  };
}

function executeApplyStatus(
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
): EffectExecutorResult {
  if (effect.applyStatus === null) {
    return missingPayload(state, effect, ctx);
  }

  const { status, duration } = effect.applyStatus;
  if (!isStatusId(status)) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      "apply_status.status must be a known status",
      ctx
    );
  }

  const durationBounds = bounds.statusVocabulary.durationTurns[status];
  if (!isSafeIntegerInBounds(duration, durationBounds)) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      `${status} duration must be ${durationBounds.min}-${durationBounds.max}`,
      ctx
    );
  }

  const targetId = resolveStatusTargetId(state, ctx);
  if (targetId === null) {
    return invalidTarget(
      state,
      effect,
      ctx,
      "apply_status requires an existing target"
    );
  }

  const applied = applyStatus(state, targetId, status, duration);

  return {
    state: applied.state,
    events: [
      effectExecutedEvent(
        state,
        "apply_status",
        withResolvedTarget(ctx, targetId),
        {
          status,
          duration
        }
      ),
      ...applied.events
    ]
  };
}

function executeCureStatus(
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
): EffectExecutorResult {
  if (effect.cureStatus === null) {
    return missingPayload(state, effect, ctx);
  }

  const status = effect.cureStatus.status;
  if (
    status !== bounds.effectVocabulary.verbs.cureStatus.allKeyword &&
    !isStatusId(status)
  ) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      "cure_status.status must be a known status or all",
      ctx
    );
  }

  const targetId = resolveStatusTargetId(state, ctx);
  if (targetId === null) {
    return invalidTarget(
      state,
      effect,
      ctx,
      "cure_status requires an existing target"
    );
  }

  const previousStatuses = statusesForEntity(state, targetId);
  const nextStatuses =
    status === bounds.effectVocabulary.verbs.cureStatus.allKeyword
      ? []
      : previousStatuses.filter((entry) => entry.status !== status);
  const curedCount = previousStatuses.length - nextStatuses.length;

  return {
    state: withEntityStatuses(state, targetId, nextStatuses),
    events: [
      effectExecutedEvent(
        state,
        "cure_status",
        withResolvedTarget(ctx, targetId),
        {
          status,
          curedCount
        }
      )
    ]
  };
}

function executeBuffStat(
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
): EffectExecutorResult {
  if (effect.buffStat === null) {
    return missingPayload(state, effect, ctx);
  }

  const { stat, magnitude, duration } = effect.buffStat;
  const magnitudeBounds = bounds.effectVocabulary.verbs.buffStat.magnitudeAbs;
  const durationBounds = bounds.effectVocabulary.verbs.buffStat.durationTurns;
  if (stat !== "ATK" && stat !== "DEF") {
    return rejectEffect(
      state,
      effect,
      "bounds",
      "buff_stat.stat must be ATK or DEF",
      ctx
    );
  }

  if (
    !isSafeInteger(magnitude) ||
    Math.abs(magnitude) < magnitudeBounds.min ||
    Math.abs(magnitude) > magnitudeBounds.max
  ) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      `buff_stat.magnitude absolute value must be ${magnitudeBounds.min}-${magnitudeBounds.max}`,
      ctx
    );
  }

  if (!isSafeIntegerInBounds(duration, durationBounds)) {
    return rejectEffect(
      state,
      effect,
      "bounds",
      `buff_stat.duration must be ${durationBounds.min}-${durationBounds.max}`,
      ctx
    );
  }

  const target = resolveHpTarget(state, ctx);
  if (target === null) {
    return invalidTarget(
      state,
      effect,

    }
  }

  nextState = appendLog(nextState, events);

  return {
    state: nextState,
    events,
  };
};

export const render = (state: GameState): string =>
  [
    `run=${state.run.runId}`,
