const invalidTarget = (
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext,
  message: string
): EffectExecutorResult =>
  rejectEffect(state, effect, "invalid_target", message, ctx);

const withResolvedTarget = (
  ctx: EffectExecutionContext,
  targetId: EffectActorId
): EffectExecutionContext => ({
  ...ctx,
  targetId
});

const isSafeInteger = (value: unknown): value is number =>
  typeof value === "number" && Number.isSafeInteger(value);

const isSafeIntegerInBounds = (
  value: unknown,
  range: { readonly min: number; readonly max: number }
): value is number =>
  isSafeInteger(value) && value >= range.min && value <= range.max;

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.length > 0;

const STATUS_IDS: ReadonlySet<string> = new Set(
  bounds.statusVocabulary.closedList
);

const isStatusId = (value: unknown): value is StatusId =>
  typeof value === "string" && STATUS_IDS.has(value);

const ITEM_CATEGORIES: ReadonlySet<string> = new Set([
  "weapon",
  "armor",
  "charm",
  "draught",
  "note",
  "throwable",
  "food",
  "tool",
  "key_item",
  "coin"
] satisfies readonly ItemCategory[]);

const isItemCategory = (value: unknown): value is ItemCategory =>
  typeof value === "string" && ITEM_CATEGORIES.has(value);

import { bounds } from "../../config/index.js";
import type {
  Effect,
  EffectBundle,
  EffectVerbKind
} from "../../schemas/vocab/index.js";
import type { Rng } from "../rng/index.js";
import type {
  EngineLogEventDataByType,
  EntityId,
  GameState,
  Position,
  SerializableRecord
} from "../state/index.js";
import type { TurnEvent } from "../turn/index.js";

export type EffectActorId = "player" | EntityId;

export type EffectRejectionCode =
  | "bundle_size"
  | "bounds"
  | "invalid_target"
  | "missing_payload"
  | "unregistered_executor";

export type EffectExecutionContext = {
  readonly sourceId: EffectActorId | null;
  readonly targetId: EffectActorId | null;
  readonly origin: Position | null;
  readonly rng: Rng;
};

export type EffectExecutorResult = {
  readonly state: GameState;
  readonly events: readonly TurnEvent[];
  readonly rejected?: true;
};

export type EffectExecutor = (
  state: GameState,
  effect: Effect,
  ctx: EffectExecutionContext
) => EffectExecutorResult;

declare module "../state/types.js" {
  interface EngineLogEventDataByType {
    readonly effect_executed: {
      readonly verb: EffectVerbKind;
      readonly sourceId: EffectActorId | null;
      readonly targetId: EffectActorId | null;
      readonly origin: Position | null;
      readonly details: SerializableRecord;
    };
    readonly effect_rejected: {
      readonly verb: EffectVerbKind | "bundle";
      readonly effectIndex: number | null;
      readonly code: EffectRejectionCode;
      readonly message: string;
      readonly sourceId: EffectActorId | null;
      readonly targetId: EffectActorId | null;
      readonly origin: Position | null;
    };
  }
}

type EffectLogEventType = "effect_executed" | "effect_rejected";

const executors = new Map<EffectVerbKind, EffectExecutor>();

export const registerEffectExecutor = (
  verb: EffectVerbKind,
  executor: EffectExecutor
): (() => void) => {
  const previous = executors.get(verb);
  executors.set(verb, executor);

  return () => {
    if (executors.get(verb) !== executor) {
      return;
    }

    if (previous === undefined) {
      executors.delete(verb);
      return;
    }

    executors.set(verb, previous);
  };
};

export const executeBundle = (
  state: GameState,
  bundle: EffectBundle,
  ctx: EffectExecutionContext
): EffectExecutorResult => {
  if (!isBundleSizeInBounds(bundle.effects.length)) {
    return rejectEffectBundle(
      state,
      "bundle_size",
      `effect bundle must contain ${bounds.effectVocabulary.effectsPerBundle.min}-${bounds.effectVocabulary.effectsPerBundle.max} effects`,
      ctx
    );
  }

  const events: TurnEvent[] = [];
  const executionCtx = {
    ...ctx,
    rng: ctx.rng.fork("effects")
  };
  let nextState = state;

  for (let index = 0; index < bundle.effects.length; index += 1) {
    const effect = bundle.effects[index];
    if (effect === undefined) {
      return rejectEffectBundle(
        state,
        "bounds",
        `effect at index ${index} is missing`,
        executionCtx
      );
    }

    const executor = executors.get(effect.kind);
    if (executor === undefined) {
      return {
        state,
        events: [
          effectRejectedEvent(state, effect.kind, {
            code: "unregistered_executor",
            message: `no executor registered for ${effect.kind}`,
            ctx: executionCtx,
            effectIndex: index
          })
        ],
        rejected: true
      };
    }

    const result = executor(nextState, effect, executionCtx);
    if (result.rejected === true) {
      return {
        state,
        events: withEffectIndex(result.events, index),
        rejected: true
      };
    }

    nextState = result.state;
    events.push(...result.events);
  }

  return {
    state: nextState,
    events
  };
};

export const effectExecutedEvent = (
  state: GameState,
  verb: EffectVerbKind,
  ctx: EffectExecutionContext,
  details: SerializableRecord = {}
): TurnEvent =>
  effectEvent(state, "effect_executed", {
    verb,
    sourceId: ctx.sourceId,
    targetId: ctx.targetId,
    origin: ctx.origin,
    details
  });

export const rejectEffect = (
  state: GameState,
  effect: Effect,
  code: EffectRejectionCode,
  message: string,
  ctx: EffectExecutionContext
): EffectExecutorResult => ({
  state,
  events: [
    effectRejectedEvent(state, effect.kind, {
      code,
      message,
      ctx,
      effectIndex: null
    })
  ],
  rejected: true
});

const rejectEffectBundle = (
  state: GameState,
  code: EffectRejectionCode,
  message: string,
  ctx: EffectExecutionContext
): EffectExecutorResult => ({
  state,
  events: [
    effectRejectedEvent(state, "bundle", {
      code,
      message,
      ctx,
      effectIndex: null
    })
  ],
  rejected: true
});

const effectRejectedEvent = (
  state: GameState,
  verb: EffectVerbKind | "bundle",
  options: {
    readonly code: EffectRejectionCode;
    readonly message: string;
    readonly ctx: EffectExecutionContext;
    readonly effectIndex: number | null;
  }
): TurnEvent =>
  effectEvent(state, "effect_rejected", {
    verb,
    effectIndex: options.effectIndex,
    code: options.code,
    message: options.message,
    sourceId: options.ctx.sourceId,
    targetId: options.ctx.targetId,
    origin: options.ctx.origin
  });

const withEffectIndex = (
  events: readonly TurnEvent[],
  effectIndex: number
): readonly TurnEvent[] =>
  events.map((event) => {
    if (event.type !== "effect_rejected") {
      return event;
    }

    return {
      ...event,
      data: {
        ...event.data,
        effectIndex
      }
    };
  });

const effectEvent = <Type extends EffectLogEventType>(
  state: GameState,
  type: Type,
  data: EngineLogEventDataByType[Type]
): Extract<TurnEvent, { readonly type: Type }> =>
  ({
    turn: state.run.turn,
    type,
    data
  }) as Extract<TurnEvent, { readonly type: Type }>;

const isBundleSizeInBounds = (length: number): boolean =>
  Number.isSafeInteger(length) &&
  length >= bounds.effectVocabulary.effectsPerBundle.min &&
  length <= bounds.effectVocabulary.effectsPerBundle.max;

import type { TargetingShape } from "../../schemas/vocab/index.js";
import { canSee } from "../map/fov.js";
import {
  chebyshevDistance,
  discCells,
  getTile,
  inBounds,
  line,
  type TileGrid
} from "../map/grid.js";
import { isTransparentTile, isWalkableTile } from "../map/terrain.js";
import type {
  EntityId,
  EntityInstance,
  GameState,
  Position
} from "../state/index.js";
import { gridFromState } from "../turn/actions.js";

export type TargetingContext = {
  readonly originActorId: EntityId | "player";
  readonly targetCell?: Position;
};

export type TargetingGeometryResult = {
  readonly cells: readonly Position[];
  readonly entityIds: readonly (EntityId | "player")[];
};

export const resolveTargetingGeometry = (
  state: GameState,
  origin: Position,
  targeting: TargetingShape,
  context: TargetingContext
): TargetingGeometryResult => {
  const grid = gridFromState(state);

  if (grid === null) {
    return emptyResult();
  }

  switch (targeting.kind) {
    case "self":
      return resolveSelf(origin, context.originActorId);
    case "melee":
      return resolveMelee(state, grid, origin, context.targetCell);
    case "bolt":
      return resolveBolt(
        state,
        grid,
        origin,
        context.targetCell,
        targeting.bolt?.rangeTiles ?? 0,
        context.originActorId
      );
    case "burst":
      return resolveBurst(
        state,
        grid,
        origin,
        context.targetCell,
        targeting.burst?.radiusTiles ?? 0,
        targeting.burst?.center ?? "self"
      );
    case "floor":
      return resolveFloor(state, grid);
  }
};

const emptyResult = (): TargetingGeometryResult => ({
  cells: [],
  entityIds: []
});

const resolveSelf = (
  origin: Position,
  originActorId: EntityId | "player"
): TargetingGeometryResult => ({
  cells: [origin],
  entityIds: [originActorId]
});

const resolveMelee = (
  state: GameState,
  grid: TileGrid,
  origin: Position,
  targetCell: Position | undefined
): TargetingGeometryResult => {
  if (targetCell === undefined || !inBounds(grid, targetCell)) {
    return emptyResult();
  }

  if (
    samePosition(origin, targetCell) ||
    chebyshevDistance(origin, targetCell) > 1
  ) {
    return emptyResult();
  }

  return {
    cells: [targetCell],
    entityIds: entitiesAt(state, targetCell)
  };
};

const resolveBolt = (
  state: GameState,
  grid: TileGrid,
  origin: Position,
  targetCell: Position | undefined,
  range: number,
  excludeActorId: EntityId | "player"
): TargetingGeometryResult => {
  if (targetCell === undefined || range <= 0) {
    return emptyResult();
  }

  const lineCells = line(origin, targetCell).slice(1, range + 1);
  const cells: Position[] = [];

  for (const cell of lineCells) {
    if (!inBounds(grid, cell)) {
      break;
    }

    const tile = getTile(grid, cell);

    if (!isTransparentTile(tile)) {
      break;
    }

    cells.push(cell);

    const occupants = entitiesAt(state, cell).filter(
      (id) => id !== excludeActorId
    );

    if (occupants.length > 0) {
      const hasLineOfSight = canSee(grid, origin, cell, { radius: range });

      return {
        cells,
        entityIds: hasLineOfSight ? occupants : []
      };
    }
  }

  return { cells, entityIds: [] };
};

const resolveBurst = (
  state: GameState,
  grid: TileGrid,
  origin: Position,
  targetCell: Position | undefined,
  radius: number,
  center: "self" | "impact"
): TargetingGeometryResult => {
  if (radius <= 0) {
    return emptyResult();
  }

  const burstCenter = center === "impact" ? targetCell : origin;

  if (burstCenter === undefined || !inBounds(grid, burstCenter)) {
    return emptyResult();
  }

  const cells = discCells(burstCenter, radius, grid);
  const entityIds = uniqueSortedIds(
    cells.flatMap((cell) => entitiesAt(state, cell))
  );

  return { cells, entityIds };
};

const resolveFloor = (
  state: GameState,
  grid: TileGrid
): TargetingGeometryResult => {
  const cells: Position[] = [];

  for (let y = 0; y < grid.height; y += 1) {
    for (let x = 0; x < grid.width; x += 1) {
      const position = { x, y };

      if (isWalkableTile(getTile(grid, position))) {
        cells.push(position);
      }
    }
  }

  const entityIds = uniqueSortedIds(
    cells.flatMap((cell) => entitiesAt(state, cell))
  );

  return { cells, entityIds };
};

const entitiesAt = (
  state: GameState,
  position: Position
): readonly (EntityId | "player")[] => {
  const ids: (EntityId | "player")[] = [];

  if (samePosition(state.player.position, position)) {
    ids.push("player");
  }

  for (const entity of sortedEntities(state)) {
    if (samePosition(entity.position, position)) {
      ids.push(entity.id);
    }
  }

  return ids;
};

const sortedEntities = (state: GameState): readonly EntityInstance[] =>
  Object.values(state.entities).sort((left, right) =>
    left.id.localeCompare(right.id)
  );

const uniqueSortedIds = (
  ids: readonly (EntityId | "player")[]
): readonly (EntityId | "player")[] => [...new Set(ids)].sort(compareActorId);

const compareActorId = (
  left: EntityId | "player",
  right: EntityId | "player"
): number => {
  if (left === "player") {
    return right === "player" ? 0 : -1;
  }

  if (right === "player") {
    return 1;
  }

  return left.localeCompare(right);
};

const samePosition = (left: Position, right: Position): boolean =>
  left.x === right.x && left.y === right.y;

